spec.expr:
label_replace(
  node_memory_SwapTotal_bytes{job=~"$job", instance=~"$instance"}
  -
  node_memory_SwapFree_bytes{job=~"$job", instance=~"$instance"},
  "instance", "$1", "instance", "^[^:]+:[^:]+:[^:]+:(.+)"
)

label_replace(
  (
    node_memory_SwapTotal_bytes{job=~"$job", instance=~"$instance"} 
    - node_memory_SwapFree_bytes{job=~"$job", instance=~"$instance"}
  )
  /
  node_memory_SwapTotal_bytes{job=~"$job", instance=~"$instance"},
  "instance", "$1", "instance", "^[^:]+:[^:]+:[^:]+:(.+)"
)

(
  node_filesystem_size_bytes{job=~"$job", instance=~"$instance", fstype!~"tmpfs|overlay|fuse.lxcfs", mountpoint!~"/run.*|/boot.*|/etc/pve|/usr.*|/oem"} 
  - node_filesystem_free_bytes{job=~"$job", instance=~"$instance", fstype!~"tmpfs|overlay|fuse.lxcfs", mountpoint!~"/run.*|/boot.*|/etc/pve|/usr.*|/oem"}
)
/
node_filesystem_size_bytes{job=~"$job", instance=~"$instance", fstype!~"tmpfs|overlay|fuse.lxcfs", mountpoint!~"/run.*|/boot.*|/etc/pve|/usr.*|/oem"}

label_replace(
  label_join(
    label_replace(
      (
        node_network_info{job=~"$job", instance=~"$instance", device!~"cali.*|cilium.*|lxc.*|fw.*|lo"}
      )
      and on(instance, device) node_network_up{job=~"$job", instance=~"$instance", device!~"cali.*|cilium.*|lxc.*|fw.*|lo"}
      > 0,
    "instance", "$1", "instance", "^[^:]+:[^:]+:[^:]+:(.+)"
  ),
  "instancedevice", ":", "instance", "device"),
"instancedevice", "$1", "instance", "([^:]+):.*")

label_replace(
    sum(
        rate(
            node_disk_reads_completed_total{job=~"$job", instance=~"$instance", device!~"dm.*|sr0"}[1m]
            )
        )
    by (instance, device)
    > 0,
    "instance", "$1", "instance", "^[^:]+:[^:]+:[^:]+:(.+)"
)

label_replace(
    sum(
        rate(
            node_disk_writes_completed_total{job=~"$job", instance=~"$instance", device!~"dm.*|sr0"}[1m]
            )
        )
    by (instance, device)
    > 0,
    "instance", "$1", "instance", "^[^:]+:[^:]+:[^:]+:(.+)"
)

(
  node_filesystem_size_bytes{job=~"$job", instance=~"$instance", fstype!~"tmpfs|overlay|fuse.lxcfs", mountpoint!~"/run.*|/boot.*|/etc/pve|/usr.*|/oem"} 
  - node_filesystem_free_bytes{job=~"$job", instance=~"$instance", fstype!~"tmpfs|overlay|fuse.lxcfs", mountpoint!~"/run.*|/boot.*|/etc/pve|/usr.*|/oem"}
)
/
node_filesystem_size_bytes{job=~"$job", instance=~"$instance", fstype!~"tmpfs|overlay|fuse.lxcfs", mountpoint!~"/run.*|/boot.*|/etc/pve|/usr.*|/oem"}

label_replace(
    sum(
        rate(
            node_disk_read_bytes_total{job=~"$job", instance=~"$instance", device!~"dm.*|sr0"}[1m]
            )
        )
    by (instance, device)
    > 0,
    "instance", "$1", "instance", "^[^:]+:[^:]+:[^:]+:(.+)"
)

label_replace(
    sum(
        rate(
            node_disk_written_bytes_total{job=~"$job", instance=~"$instance", device!~"dm.*|sr0"}[1m]
            )
        )
    by (instance, device)
    > 0,
    "instance", "$1", "instance", "^[^:]+:[^:]+:[^:]+:(.+)"
)

label_replace(
    sum(
        node_filefd_allocated{job=~"$job", instance=~"$instance"} 
        /
        node_filefd_maximum{job=~"$job", instance=~"$instance"}
    )
    by (instance),
    "instance", "$1", "instance", "^[^:]+:[^:]+:[^:]+:(.+)"
)

label_replace(
    avg(
        1 - rate(
            node_cpu_seconds_total{job=~"$job", instance=~"$instance", mode="idle"}[1m]
            )
        )
    by (instance),
   "instance", "$1", "instance", "^[^:]+:[^:]+:[^:]+:(.+)"
)

label_replace(
  node_memory_MemTotal_bytes{job=~"$job", instance=~"$instance"}
  -
  node_memory_MemAvailable_bytes{job=~"$job", instance=~"$instance"},
  "instance", "$1", "instance", "^[^:]+:[^:]+:[^:]+:(.+)"
)

label_replace(
  (
    node_memory_MemTotal_bytes{job=~"$job", instance=~"$instance"} 
    - node_memory_MemAvailable_bytes{job=~"$job", instance=~"$instance"}
  )
  /
  node_memory_MemTotal_bytes{job=~"$job", instance=~"$instance"},
  "instance", "$1", "instance", "^[^:]+:[^:]+:[^:]+:(.+)"
)
